+// just an exported helper; to avoid link time elimination of the referenced functions
+extern "C" JNIEXPORT void JVM_debug_helpers_keeper(void* p1, void* p2, void* p3, intptr_t ip, oop oh, address adr) {
+  blob((CodeBlob*)p1);
+  dump_vtable(adr);
+  nm(ip);
+  disnm(ip);
+  printnm(ip);
+  universe();
+  verify();
+  pp(p1);
+  ps();
+  pfl();
+  psf();
+  threads();
+  psd();
+  pss();
+  debug();
+  ndebug();
+  flush();
+  events();
+  findm(ip);
+  findnm(ip);
+  find(ip);
+  findpc(ip);
+  findclass("", 0);
+  findmethod("", "", 0);
+  findbcp(ip, ip);
+  u5decode(ip);
+  u5p(ip, ip, 0);
+  pp(ip);
+  pp(oh);
+  help();
+#ifndef PRODUCT
+  pns(p1, p2, p3);
+  pns2();
+#endif
+}
